import openai
import base64
import json

client = openai.OpenAI()

def analyze_call_natively(audio_path: str) -> dict:
    """Send audio directly to a native multimodal model."""
    with open(audio_path, "rb") as f:
        audio_b64 = base64.b64encode(f.read()).decode("utf-8")

    # Detect format from extension
    ext = audio_path.rsplit(".", 1)[-1].lower()
    mime = {"mp3": "audio/mpeg", "wav": "audio/wav", "flac": "audio/flac"}.get(ext, "audio/wav")

    response = client.chat.completions.create(
        model="gpt-4o-audio-preview",
        modalities=["text"],
        messages=[
            {
                "role": "system",
                "content": (
                    "You are a call quality analyst. Listen carefully to tone, "
                    "urgency, and emotion in addition to words. Return JSON with: "
                    "summary, urgency_level (1-5), detected_emotion, action_items."
                ),
            },
            {
                "role": "user",
                "content": [
                    {
                        "type": "input_audio",
                        "input_audio": {"data": audio_b64, "format": ext},
                    },
                    {"type": "text", "text": "Analyze this support call."},
                ],
            },
        ],
        response_format={"type": "json_object"},
    )
    return json.loads(response.choices[0].message.content)


result = analyze_call_natively("escalation_call.mp3")
print(f"Urgency: {result['urgency_level']}/5 | Emotion: {result['detected_emotion']}")
print(f"Summary: {result['summary']}")
for item in result.get("action_items", []):
    print(f"  - {item}")

